// Генерируем ВСЕ месяцы с 2021-01-01 по сегодня для contracts
const startDate = new Date('2021-01-01');
const endDate = new Date();
const periods = [];

let current = new Date(startDate);
let idx = 0;

while (current <= endDate) {
  const periodStart = new Date(current);
  const periodEnd = new Date(current.getFullYear(), current.getMonth() + 1, 0); // Последний день месяца

  const actualEnd = periodEnd > endDate ? endDate : periodEnd;

  periods.push({
    json: {
      idx: idx++,
      date_from: periodStart.toISOString().split('T')[0],
      date_to: actualEnd.toISOString().split('T')[0],
      year: periodStart.getFullYear(),
      month: periodStart.getMonth() + 1
    }
  });

  // Переходим к первому дню следующего месяца
  current = new Date(current.getFullYear(), current.getMonth() + 1, 1);
}

console.log(`Generated ${periods.length} monthly periods for contracts`);
return periods;

// Генерируем ВСЕ недели с 2021-01-01 по сегодня для driver-reports
// API не переваривает большие периоды, поэтому бьём по неделям
const startDate = new Date('2021-01-01');
const endDate = new Date();
const weeks = [];

let current = new Date(startDate);
let idx = 0;

while (current <= endDate) {
  const weekStart = new Date(current);
  const weekEnd = new Date(current);
  weekEnd.setDate(weekEnd.getDate() + 6); // 7-дневный период

  const actualEnd = weekEnd > endDate ? endDate : weekEnd;

  weeks.push({
    json: {
      idx: idx++,
      date_from: weekStart.toISOString().split('T')[0],
      date_to: actualEnd.toISOString().split('T')[0]
    }
  });

  // Переходим к следующей неделе
  current.setDate(current.getDate() + 7);
}

console.log(`Generated ${weeks.length} weekly periods for driver-reports`);
return weeks;

