// Собираем contracts из всех месяцев
const items = $input.all();
const allContracts = [];

function esc(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/'/g, "''");
}

for (const item of items) {
  let contracts = item.json;
  if (!Array.isArray(contracts)) {
    if (contracts && typeof contracts === 'object' && contracts.number) contracts = [contracts];
    else continue;
  }

  for (const c of contracts) {
    const number = esc(c.number || c.Номер || '');
    const date = c.date || c.Дата || null;
    if (number && date) {
      allContracts.push({
        json: {
          number, date,
          organization: esc(c.organization || ''),
          contractor_id: esc(c.contractor_id || ''),
          contractor_name: esc(c.contractor_name || ''),
          vehicle_id: esc(c.vehicle_id || ''),
          vehicle_number: esc(c.vehicle_number || ''),
          driver_id: esc(c.driver_id || ''),
          driver_name: esc(c.driver_name || ''),
          responsible_logist: esc(c.responsible_logist || ''),
          route: esc(c.route || ''),
          payment_term: esc(c.payment_term || ''),
          payment_condition: esc(c.payment_condition || ''),
          amount: parseFloat(c.amount || 0) || 0
        }
      });
    }
  }
}

console.log('Total contracts:', allContracts.length);
return allContracts;

// Собираем все отчёты из всех недель
const items = $input.all();
const allReports = [];

function esc(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/'/g, "''");
}

function parseNum(val) {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return val;
  const cleaned = String(val).replace(/\s/g, '').replace(',', '.');
  return parseFloat(cleaned) || 0;
}

for (const item of items) {
  let reports = item.json;
  if (!Array.isArray(reports)) {
    if (reports && typeof reports === 'object' && reports.id) reports = [reports];
    else continue;
  }

  for (const r of reports) {
    if (!r.id) continue;
    allReports.push({
      json: {
        id: esc(r.id),
        number: esc(r.number || ''),
        date_from: r.date_from || null,
        date_to: r.date_to || null,
        driver_id: esc(r.driver_id || ''),
        driver_name: esc(r.driver_name || ''),
        vehicle_id: esc(r.vehicle_id || ''),
        vehicle_number: esc(r.vehicle_number || ''),
        fuel_start: parseNum(r.fuel_start),
        fuel_end: parseNum(r.fuel_end),
        mileage: Math.round(parseNum(r.mileage)),
        fuel_quantity: parseNum(r.fuel_quantity),
        fuel_amount: parseNum(r.fuel_amount),
        total_expenses: parseNum(r.total_expenses),
        driver_accruals: parseNum(r.driver_accruals),
        driver_payments: parseNum(r.driver_payments),
        expense_categories: JSON.stringify(r.expense_categories || [])
      }
    });
  }
}

console.log('Total driver reports:', allReports.length);
return allReports;

